#!/usr/bin/env node

/**
 * envx CLI
 *
 * Commands:
 *   envx check   – Validate current .env against envx.config.js
 *   envx init    – Generate a starter envx.config.js from current .env
 */

import { loadFile } from "../src/parser.js";
import { validate } from "../src/validator.js";
import { loadConfig } from "../src/configLoader.js";
import { writeFileSync, existsSync } from "fs";
import { resolve } from "path";

const [, , command, ...args] = process.argv;

const HELP = `
Usage: envx <command>

Commands:
  check         Validate .env against your envx.config.js schema
  init          Generate a starter envx.config.js from your .env file
  help          Show this help message

Options:
  --path <file>   Path to .env file (default: .env)
  --debug         Print resolved values after loading

Examples:
  envx check
  envx check --path .env.production
  envx init
`;

async function cmdCheck() {
  const pathFlag = args.indexOf("--path");
  const envPath = pathFlag !== -1 ? args[pathFlag + 1] : undefined;
  const debug = args.includes("--debug");

  console.log("\n🔍 envx: checking environment...\n");

  // Load .env
  const fileVars = loadFile(envPath);
  const merged = { ...fileVars, ...process.env };

  // Load schema
  const config = await loadConfig();

  if (!config) {
    console.log("ℹ️  No envx.config.js found — nothing to validate against.\n");
    console.log(`   Loaded ${Object.keys(fileVars).length} variable(s) from .env.\n`);
    console.log("   Run `envx init` to generate a config file.\n");
    process.exit(0);
  }

  const { schema, strict } = config;
  const { result, errors } = validate(merged, schema, strict);

  if (errors.length > 0) {
    console.error("❌ ENV VALIDATION FAILED\n");
    for (const err of errors) {
      console.error(`  - ${err}`);
    }
    console.error("");
    process.exit(1);
  }

  console.log("✅ All environment variables are valid.\n");

  if (debug) {
    console.log("Resolved values:");
    for (const [key, val] of Object.entries(result)) {
      const isSecret =
        key.toLowerCase().includes("secret") ||
        key.toLowerCase().includes("password") ||
        key.toLowerCase().includes("key") ||
        key.toLowerCase().includes("token");
      console.log(`  ${key} = ${isSecret ? "***" : JSON.stringify(val)}`);
    }
    console.log("");
  }
}

async function cmdInit() {
  const pathFlag = args.indexOf("--path");
  const envPath = pathFlag !== -1 ? args[pathFlag + 1] : undefined;
  const outPath = resolve(process.cwd(), "envx.config.js");

  if (existsSync(outPath)) {
    console.error("⚠️  envx.config.js already exists. Remove it first to regenerate.\n");
    process.exit(1);
  }

  const fileVars = loadFile(envPath);
  const keys = Object.keys(fileVars);

  if (keys.length === 0) {
    console.log("ℹ️  No variables found in .env — generating empty config.\n");
  }

  // Heuristically guess types
  function guessType(key, value) {
    if (!isNaN(Number(value))) return "number";
    const lower = value.toLowerCase();
    if (["true", "false", "1", "0", "yes", "no"].includes(lower)) return "boolean";
    try { new URL(value); return "url"; } catch {}
    if (/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) return "email";
    try { JSON.parse(value); return "json"; } catch {}
    return "string";
  }

  function guessRequired(key) {
    const upper = key.toUpperCase();
    return (
      upper.includes("KEY") ||
      upper.includes("SECRET") ||
      upper.includes("TOKEN") ||
      upper.includes("PASSWORD") ||
      upper.includes("DATABASE_URL") ||
      upper.includes("API_")
    );
  }

  const entries = keys.map((key) => {
    const val = fileVars[key];
    const type = guessType(key, val);
    const required = guessRequired(key);

    let ruleStr = `  ${key}: { type: "${type}"`;
    if (required) {
      ruleStr += `, required: true`;
    } else {
      const defaultVal = type === "number" ? Number(val) : type === "boolean" ? val.toLowerCase() === "true" : val;
      ruleStr += `, default: ${JSON.stringify(defaultVal)}`;
    }
    ruleStr += ` }`;
    return ruleStr;
  });

  const content = `// Generated by envx init
// Edit this file to add validation rules for your environment variables.
// Docs: https://github.com/munesoft/envx

export default {
  // strict: true, // Uncomment to disallow variables not listed here
${entries.join(",\n")}
};
`;

  writeFileSync(outPath, content, "utf8");
  console.log(`✅ Generated envx.config.js with ${keys.length} variable(s).\n`);
  console.log("   Review and adjust types, required flags, and defaults.\n");
}

// Route commands
switch (command) {
  case "check":
    await cmdCheck();
    break;

  case "init":
    await cmdInit();
    break;

  case "help":
  case "--help":
  case "-h":
  case undefined:
    console.log(HELP);
    break;

  default:
    console.error(`\n❌ Unknown command: ${command}\n`);
    console.log(HELP);
    process.exit(1);
}
